      "content": "const router = require('express').Router();
tasksService = require('./service');
const { sendError } = require('../../lib/errors');

router.post('/', async (req, res) => {
  const name = String(req.body?.name || '').trim();
  if (!name) return sendError(res, 400, 'BAD_REQUEST', 'Task name is required');
  const task = await tasksService.createTask(req.params.projectId, name);
  if (!task) return sendError(res, 500, 'INTERNAL_ERROR', 'Failed to create task');
  return res.status(201).json({ task });
});

router.get('/', async (req, res) => {
  const status = req.query.status;
  let tasks;
  if (status === 'done') {
    tasks = await tasksService.getDoneTasksByProjectId(req.params.projectId);
  } else {
    tasks = await tasksService.getAllTasksByProjectId(req.params.projectId);
  }
  if (!tasks) return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
  return res.json({ tasks });
});

router.patch('/:taskId', async (req, res) => {
  const { status } = req.body;
  if (status !== 'todo' && status !== 'done') return sendError(res, 400, 'BAD_REQUEST', 'Invalid task status');
  const task = await tasksService.updateTaskStatus(req.params.projectId, req.params.taskId, status);
  if (!task) return sendError(res, 500, 'INTERNAL_ERROR', 'Failed to update task status');
  return res.json({ task });
});

module.exports = router;
