      "path": "src/modules/tasks/service.js",
      "content": "const projectsService = require('../projects/service');
const { randomUUID } = require('node:crypto');

function createTask(projectId, name) {
  const project = projectsService.getProjectById(projectId);
  if (!project) return null;
  const task = { id: randomUUID(), name, status: 'todo', comments: [] };
  project.tasks.push(task);
  return task;
}

function getAllTasksByProjectId(projectId) {
  const project = projectsService.getProjectById(projectId);
  if (!project) return null;
  return project.tasks;
}

function getDoneTasksByProjectId(projectId) {
  const project = projectsService.getProjectById(projectId);
  if (!project) return null;
  return project.tasks.filter(task => task.status === 'done');
}

function updateTaskStatus(projectId, taskId, status) {
  const project = projectsService.getProjectById(projectId);
  if (!project) return null;
  const task = project.tasks.find(t => t.id === taskId);
  if (!task) return null;
  task.status = status;
  return task;
}

module.exports = {
  createTask,
  getAllTasksByProjectId,
  getDoneTasksByProjectId,
  updateTaskStatus,
};
